        DrawStandardLabel(new Rect(rect.x + 18f, rect.y + 8f, 190f, 22f), "使用 " + itemName, smallStyle);

        Die selectedDie = selectedMarketDieIndex >= 0 && selectedMarketDieIndex < dice.Count ? dice[selectedMarketDieIndex] : null;
