            case "feed_quality_start":
                feedQualityStart = Mathf.Max(1, value);
                if (!hasSave)
                {
                    feedQuality = feedQualityStart;
                }
                return true;
            case "market_refresh_cost_step":
                marketRefreshCostStep = Mathf.Max(0, value);
                return true;
            case "affix_feature_enabled":
